func (o *RaceGrid) Preload(name string, retrieved any) error {
	if o == nil {
		return nil
	}

	switch name {
	case "BookingEntries":
		rels, ok := retrieved.(BookingEntrySlice)
		if !ok {
			return fmt.Errorf("raceGrid cannot load %T as %q", retrieved, name)
		}

		o.R.BookingEntries = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.RaceGrid = o
			}
		}
		return nil
	case "ImportBatches":
		rels, ok := retrieved.(ImportBatchSlice)
		if !ok {
			return fmt.Errorf("raceGrid cannot load %T as %q", retrieved, name)
		}

		o.R.ImportBatches = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.RaceGrid = o
			}
		}
		return nil
	case "Race":
		rel, ok := retrieved.(*Race)
		if !ok {
			return fmt.Errorf("raceGrid cannot load %T as %q", retrieved, name)
		}

		o.R.Race = rel

		if rel != nil {
			rel.R.RaceGrids = RaceGridSlice{o}
		}
		return nil
	case "ResultEntries":
		rels, ok := retrieved.(ResultEntrySlice)
		if !ok {
			return fmt.Errorf("raceGrid cannot load %T as %q", retrieved, name)
		}

		o.R.ResultEntries = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.RaceGrid = o
			}
		}
		return nil
	default:
		return fmt.Errorf("raceGrid has no relationship %q", name)
	}
}

type raceGridPreloader struct {
	Race func(...psql.PreloadOption) psql.Preloader
}

func buildRaceGridPreloader() raceGridPreloader {
	return raceGridPreloader{
		Race: func(opts ...psql.PreloadOption) psql.Preloader {
			return psql.Preload[*Race, RaceSlice](psql.PreloadRel{
				Name: "Race",
				Sides: []psql.PreloadSide{
					{
						From:        RaceGrids,
						To:          Races,
						FromColumns: []string{"race_id"},
						ToColumns:   []string{"id"},
					},
				},
			}, Races.Columns.Names(), opts...)
		},
	}
}

